    "    'job_title',\n",
    "    'company',\n",
    "    'job_location',\n",
    "    'job_level',\n",
    "    'job_type',\n",
    "    'search_position'\n",
    "]]\n",
    "\n",
    "print(\"\\nSelected Columns Dataset:\")\n",
    "print(df.head())\n",
    "\n",
    "# ============================================================\n",
    "# MODULE 4 — HANDLE MISSING VALUES\n",
    "# ============================================================\n",
    "\n",
    "# Fill missing values\n",
    "\n",
    "df['job_location'] = df['job_location'].fillna(\"Unknown\")\n",
    "\n",
    "# Remove duplicates\n",
    "\n",
    "df.drop_duplicates(inplace=True)\n",
    "\n",
    "print(\"\\nDataset Shape After Cleaning:\")\n",
    "print(df.shape)\n",
    "\n",
    "# ============================================================\n",
    "# MODULE 5 — TEXT CLEANING\n",
    "# ============================================================\n",
    "\n",
    "# Function for text cleaning\n",
    "\n",
    "def clean_text(text):\n",
    "\n",
    "    text = str(text).lower()\n",
    "\n",
    "    text = re.sub(r'[^a-zA-Z ]', '', text)\n",
    "\n",
    "    return text\n",
    "\n",
    "# Apply cleaning\n",
    "\n",
    "df['job_title'] = df['job_title'].apply(clean_text)\n",
    "\n",
    "df['company'] = df['company'].apply(clean_text)\n",
    "\n",
    "df['job_location'] = df['job_location'].apply(clean_text)\n",
    "\n",
    "df['job_level'] = df['job_level'].apply(clean_text)\n",
    "\n",
    "df['job_type'] = df['job_type'].apply(clean_text)\n",
    "\n",
    "df['search_position'] = df['search_position'].apply(clean_text)\n",
    "\n",
    "print(\"\\nCleaned Dataset:\")\n",
    "print(df.head())\n",
    "\n",
