    "# MODULE 8 — TF-IDF FEATURE EXTRACTION\n",
    "# ============================================================\n",
    "\n",
    "# Create TF-IDF vectorizer\n",
    "\n",
    "tfidf = TfidfVectorizer(\n",
    "    stop_words='english',\n",
    "    max_features=50\n",
    ")\n",
    "\n",
    "# Convert skills into vectors\n",
    "\n",
    "tfidf_features = tfidf.fit_transform(df['skills'])\n",
    "\n",
    "print(\"\\nTF-IDF Feature Shape:\")\n",
    "print(tfidf_features.shape)\n",
    "\n",
    "# ============================================================\n",
    "# MODULE 9 — NUMERIC FEATURES\n",
    "# ============================================================\n",
    "\n",
    "# Select numeric columns\n",
    "\n",
    "numeric_features = df[[\n",
    "    'location_encoded',\n",
    "    'level_encoded',\n",
    "    'type_encoded'\n",
    "]]\n",
    "\n",
    "# Scale numeric features\n",
    "\n",
    "scaler = MinMaxScaler()\n",
    "\n",
    "scaled_numeric = scaler.fit_transform(numeric_features)\n",
    "\n",
    "print(\"\\nScaled Numeric Features:\")\n",
    "print(scaled_numeric[:5])\n",
    "\n",
    "# ============================================================\n",
    "# MODULE 10 — COMBINE FEATURES\n",
    "# ============================================================\n",
    "\n",
    "# Combine TF-IDF and numeric features\n",
    "\n",
    "combined_features = hstack([\n",
    "    tfidf_features,\n",
    "    scaled_numeric\n",
