    "\n",
    "# ============================================================\n",
    "# MODULE 12 — USER PROFILE INPUT\n",
    "# ============================================================\n",
    "\n",
    "print(\"\\n\")\n",
    "print(\"=\" * 60)\n",
    "print(\"USER PROFILE INPUT\")\n",
    "print(\"=\" * 60)\n",
    "\n",
    "user_skills = input(\n",
