    "\n",
    "user_level = input(\n",
    "    \"Enter job level (associate/mid senior/etc): \"\n",
    ")\n",
    "\n",
    "user_type = input(\n",
    "    \"Enter job type (onsite/remote/hybrid): \"\n",
    ")\n",
    "\n",
    "# ============================================================\n",
    "# MODULE 13 — USER PROFILE TRANSFORMATION\n",
