    "\n",
    "user_level = clean_text(user_level)\n",
    "\n",
    "user_type = clean_text(user_type)\n",
    "\n",
    "# TF-IDF transform\n",
    "\n",
    "user_skill_vector = tfidf.transform([user_skills])\n",
