    "    'level_encoded': [user_level_encoded],\n",
    "    \n",
    "    'type_encoded': [user_type_encoded]\n",
    "})\n",
    "\n",
    "# Scale user numeric data\n",
    "\n",
    "user_scaled = scaler.transform(user_numeric)\n",
    "\n",
    "# Combine user features\n",
    "\n",
    "user_combined = hstack([\n",
    "    \n",
    "    user_skill_vector,\n",
    "    \n",
    "    user_scaled\n",
    "])\n",
    "\n",
    "# PCA transform\n",
    "\n",
    "user_reduced = pca.transform(\n",
    "    user_combined.toarray()\n",
    ")\n",
